INSERT INTO `meals` VALUES (1, 'Trứng bác rau chân vịt', 16, 1, 'B1: Đập 2 quả trứng gà vào bát, đánh đều.\nB2: Cho một ít rau chân vịt cắt nhỏ vào trộn đều.\nB3: Làm nóng chảo, thêm dầu ăn, đổ hỗn hợp vào.\n Đảo nhẹ tay 2–3 phút cho đến khi chín.', '1755337185_68a051e18d4ac.jpg', 'Món ăn sáng đơn giản, nhanh và giàu protein, phù hợp người ăn chay có trứng sữa.', '2025-08-01 17:28:55', '2025-08-22 21:25:05', NULL);
INSERT INTO `meals` VALUES (2, 'Salad Gà nướng', 5, 6, 'B1: Ướp ức gà với tiêu, muối, dầu olive trong 10 phút.\nB2: Nướng trên chảo hoặc nồi chiên không dầu ~10 phút.\nB3: Trộn cùng xà lách, cà chua bi, sốt dầu giấm.', '1755337163_68a051cba46df.JPG', 'Ức gà nướng thơm kết hợp rau xà lách tươi, cà chua bi, dưa leo và sốt mật ong chua ngọt, healthy và giàu protein.', '2025-08-01 17:33:50', '2025-08-21 20:09:40', NULL);
INSERT INTO `meals` VALUES (3, 'Tô ngũ cốc quinoa với rau', 18, 4, 'B1: Nấu quinoa với nước theo tỉ lệ 1:2 trong 15 phút.\nB2: Xào cà rốt, bí đỏ, đậu hà lan với dầu oliu.\nB3: Trộn quinoa và rau củ, rắc mè đen.', '1755337137_68a051b16d8c3.jpg', 'Bữa tối nhẹ nhàng, đầy đủ chất xơ và đạm thực vật.', '2025-08-01 17:35:42', '2025-08-24 19:48:31', NULL);
INSERT INTO `meals` VALUES (4, 'Sinh tố chuối hạnh nhân', 15, 7, 'B1: Lột vỏ 1 quả chuối, cắt khoanh.\nB2: Cho vào máy xay cùng 200ml sữa hạnh nhân.\nB3: Thêm vài viên đá, xay mịn 30 giây.', '1755337124_68a051a47f510.jpg', 'Sinh tố mát lạnh cho bữa sáng hoặc bữa phụ.', '2025-08-01 17:37:04', '2025-08-23 15:50:49', NULL);
INSERT INTO `meals` VALUES (5, 'Cá hồi nướng măng tây', 3, 4, 'B1: Ướp cá hồi với muối, tiêu, chanh.\nB2: Đặt cá và măng tây lên khay nướng.\nB3: Nướng 200°C trong 15–20 phút.', '1755337110_68a05196b737a.jpg', 'Bữa tối lành mạnh, giàu chất béo tốt.', '2025-08-01 17:37:55', '2025-08-16 16:38:30', NULL);
INSERT INTO `meals` VALUES (6, 'Táo chấm bơ đậu phộng', 16, 6, 'B1: Gọt vỏ 1 quả táo, cắt lát mỏng.\nB2: Quét một ít bơ đậu phộng lên từng lát táo.', '1755337099_68a0518b45472.jpg', 'Ăn nhẹ đơn giản, phù hợp người tiểu đường.', '2025-08-01 17:39:47', '2025-08-22 21:25:05', NULL);
INSERT INTO `meals` VALUES (7, 'Bánh mì nguyên hạt phết bơ', 16, 3, 'B1: Nướng 1 lát bánh mì nguyên cám.\nB2: Nghiền nửa quả bơ với ít muối và tiêu.\nB3: Phết bơ lên bánh mì, thêm mè đen.', '1755337085_68a0517d92733.jpg', 'Món ăn chiều nhẹ nhàng, no lâu.', '2025-08-01 17:41:12', '2025-08-22 21:25:05', NULL);
INSERT INTO `meals` VALUES (8, 'Phở Gà', 8, 1, 'B1: Luộc gà lấy nước dùng, lọc cặn.\nB2: Luộc bánh phở, xếp vào tô.\nB3: Thêm thịt gà xé, rau thơm, chan nước dùng.', '1755337074_68a0517218050.jpg', 'Phở nước dùng trong ngọt từ xương gà, thịt gà mềm thơm, sợi phở mềm ăn kèm hành tươi, rau thơm và chanh ớt.', '2025-08-01 17:42:24', '2025-08-16 16:37:54', NULL);
INSERT INTO `meals` VALUES (9, 'Bò xào bông cải xanh', 8, 14, 'B1: Cắt lát thịt bò mỏng, ướp gừng, tỏi, nước tương.\nB2: Luộc sơ bông cải.\nB3: Xào bò, sau đó cho bông cải vào đảo nhanh.', '1755337035_68a0514b4ead1.jpg', 'Thịt bò mềm xào cùng bông cải xanh giòn, tỏi thơm, nêm nếm đậm đà, giàu dinh dưỡng và dễ chế biến.', '2025-08-01 17:43:48', '2025-08-21 16:22:52', NULL);
INSERT INTO `meals` VALUES (10, 'Cháo yến mạch hạnh nhân', 18, 5, 'B1: Nấu ½ cốc yến mạch với 1 cốc sữa hạnh nhân.\nB2: Thêm hạt hạnh nhân, mật ong nếu thích.\nB3: Ăn khi còn ấm.', '1755337008_68a051306eccc.jpg', 'Bữa khuya nhẹ nhàng, dễ tiêu hoá, hỗ trợ giấc ngủ.', '2025-08-01 17:44:45', '2025-08-24 19:48:31', NULL);
INSERT INTO `meals` VALUES (11, 'Cánh gà chiên nước mắm', 16, 1, 'Mua gà\nLàm  sạch gà\nChiên gà', '1755336762_68a0503a6924a.jpg', ' Món ăn đậm đà hương vị với cánh gà vàng giòn rụm, thấm đều sốt nước mắm chua ngọt hài hòa. Thịt gà mềm bên trong, da giòn bên ngoài, kết hợp cùng tỏi, ớt, chanh tạo nên vị cay nồng, chua dịu, ngọt đậm đà. Ăn kèm cơm nóng hoặc rau sống đều hấp dẫn, phù hợp cho bữa cơm gia đình hay tiệc nhẹ.', '2025-08-05 16:06:52', '2025-08-22 21:25:05', NULL);
INSERT INTO `meals` VALUES (12, 'Bánh Crepe Chuối và Bơ Lạc', 16, 1, 'B1: Bột crepe: Trộn 100g bột mì, 1 trứng, 150ml sữa, 1 thìa dầu ăn.\nB2: Rán bánh: Đổ bột vào chảo chống dính, lật đều 2 mặt trong 2 phút.\nB3: Nhân: Phết bơ đậu phộng, xếp chuối, cuộn lại.', '1755336697_68a04ff949f19.jpg', 'Món bánh mỏng nhẹ thơm ngon với lớp vỏ crepe vàng óng, nhân chuối chín ngọt tự nhiên, rưới sốt caramel hoặc mật ong, điểm xuyến hạt óc chó giòn tan.', '2025-08-05 16:09:23', '2025-08-22 21:25:05', NULL);
INSERT INTO `meals` VALUES (13, 'Bún Thịt Nướng Chả Giò', 13, 2, 'B1: Ướp thịt: Thịt heo ướp tỏi, mật ong, nước mắm 30 phút, nướng than hoa.\nB2: Chả giò: Cuốn nhân tôm thịt, chiên giòn.\nB3: Trình bày: Xếp bún, rau, thịt, chả giò, rắc đậu phộng.', '1755336362_68a04eaad83ee.jpg', 'Món bún truyền thống với thịt nướng thơm lừng, chả giò giòn rụm, kèm rau sống tươi và nước mắm chua ngọt đậm đà.', '2025-08-10 20:34:00', '2025-08-22 21:56:14', NULL);
INSERT INTO `meals` VALUES (14, 'Súp Bí Đỏ Hạt Diêm Mạch', 2, 3, 'B1: Hấp bí: Bí đỏ cắt nhỏ hấp chín, xay nhuyễn với nước dùng.\nB2: Nấu quinoa: Luộc chín 20g quinoa trong 10 phút.\nB3: Hoàn thành: Đun súp bí, thêm quinoa, nêm gia vị.', '1755336345_68a04e993ec81.jpg', 'Súp ngọt tự nhiên từ bí đỏ, hạt quinoa dai dai giàu protein.', '2025-08-10 20:34:53', '2025-08-16 16:25:45', NULL);
INSERT INTO `meals` VALUES (15, 'Cà Ri Gà Nước Dừa', 3, 4, 'B1: Xào gia vị: Phi hành tỏi, cho bột cà ri vào đảo thơm.\nB2: Nấu gà: Cho gà vào xào săn, thêm nước dừa, khoai tây, ninh 20 phút.', '1755336332_68a04e8c91241.jpg', 'Món cà ri thơm ngon với thịt gà mềm, hòa quyện cùng nước dừa béo ngậy và gia vị đậm đà. Hương vị đặc trưng của nghệ, sả và lá chanh tạo nên món ăn hấp dẫn, ăn kèm bánh mì hoặc cơm nóng đều tuyệt vời.', '2025-08-10 20:35:45', '2025-08-16 16:25:32', NULL);
INSERT INTO `meals` VALUES (16, 'Bánh Mì Nướng Phô Mai và Tỏi', 11, 5, 'B1: Phết bơ tỏi: Trộn bơ mềm + tỏi băm + ngò.\nB2: Nướng: Phết lên bánh mì, rắc phô mai, nướng 5 phút ở 180°C.', '1755938201_68a97d99e1ff9.jpg', 'Giòn thơm từ tỏi, béo ngậy từ phô mai, hoàn hảo cho đêm muộn.', '2025-08-10 20:36:54', '2025-08-23 15:36:41', NULL);
INSERT INTO `meals` VALUES (17, 'Khoai Lang Lắc Phô Mai', 15, 6, 'B1: Cắt khoai: Khoai lang cắt que, ngâm nước muối 10 phút.\nB2: Nướng: Xếp khoai lên khay, phun dầu, nướng 25 phút ở 200°C.\nB3: Lắc phô mai: Trộn khoai nóng với phô mai bột.', '1755938048_68a97d000e422.jpg', 'Khoai Lang Lắc Phô Mai - Món ăn vặt hấp dẫn từ khoai lang vàng ươm, bùi béo, kết hợp với phô mai béo ngậy, thêm chút vị mặn ngọt hài hòa, giòn rụm khó cưỡng.', '2025-08-10 20:37:58', '2025-08-23 15:50:49', NULL);
INSERT INTO `meals` VALUES (18, 'Dứa Dừa Bạc Hà', 16, 7, 'B1: Xay: 100g dứa + 50ml nước cốt dừa + 5 lá bạc hà + đá.\nB2: Hoàn thành: Rót ra ly, thêm dừa nạo.', '1755336239_68a04e2fe005f.jpg', 'Món giải khát thanh mát kết hợp vị ngọt tự nhiên của dứa, béo ngậy từ nước cốt dừa và hương thơm tươi mát của lá bạc hà. Hoàn hảo cho ngày hè nóng bức, giúp giải nhiệt và bổ sung năng lượng.', '2025-08-10 20:39:06', '2025-08-22 21:25:05', NULL);
INSERT INTO `meals` VALUES (19, 'Khâu nhục', 13, 1, 'Muối cải\nNgâm cải muối khô\nSơ chế thịt ba chỉ\nƯớp và chiên thịt\nKho thịt với cải muối\nHấp thịt với cải muối\nHoàn thành\nThành phẩm', '1755336113_68a04db13b83a.jpg', 'Khâu nhục là món thịt kho có nguồn gốc từ Quảng Đông, Trung Quốc. Khâu nhục được du nhập vào Bắc Việt qua sự biến tấu của người dân tộc Tày, Nùng, Ngái, qua thời gian đã trở thành món ăn Đặc sản nổi tiếng của huyện Tiên Yên, Quảng Ninh và Lạng Sơn, được dùng trong những dịp gia đình có chuyện vui như lễ Tết, ...', '2025-08-11 03:03:58', '2025-08-22 21:56:14', NULL);
INSERT INTO `meals` VALUES (20, 'Sinh tố lúa mạch', 1, 1, 'Gom tiền\nĐến tập hóa, siêu thị gần nhất\nTìm loại lúa mạch phù hợp với giá tiền\nthanh toán\nvề nhà\nkhui ra\nYô~~~~~~', '1755336064_68a04d8050a38.png', 'Sinh tố lúa mạch là một thức uống bổ dưỡng và thơm ngon, được làm từ lúa mạch kết hợp với các loại trái cây, sữa, và các nguyên liệu khác. Món này không chỉ cung cấp năng lượng mà còn có nhiều lợi ích cho sức khỏe như cải thiện tiêu hóa, làm đẹp da và hỗ trợ giảm cân.', '2025-08-12 16:12:57', '2025-08-24 19:35:08', NULL);
INSERT INTO `meals` VALUES (21, 'Salad ức gà', 12, 6, 'B1:Rửa sạch rau và cà rốt.\nB2:Luộc/nướng ức gà chín.\nB3:Thái lát bơ. B4:Trộn tất cả với sốt dầu giấm.', '1755584699_68a418bb2d564.jpg', 'Salad ức gà là món ăn nhẹ nhàng, thanh mát nhưng vẫn đảm bảo đầy đủ dinh dưỡng, rất được ưa chuộng trong thực đơn lành mạnh. Nguyên liệu chính là ức gà được luộc hoặc áp chảo chín mềm, xé sợi hoặc cắt lát mỏng, kết hợp cùng các loại rau củ tươi giòn như xà lách, cà chua bi, dưa leo, bắp ngọt, cà rốt… Tất cả hòa quyện với nước sốt chua ngọt hoặc sốt mè rang, tạo nên hương vị hài hòa, dễ ăn và không gây ngán.', '2025-08-18 16:38:42', '2025-08-19 13:24:59', NULL);
INSERT INTO `meals` VALUES (22, 'Phở bò', 8, 1, 'B1:Hầm xương bò làm nước dùng.\nB2:Luộc bánh phở.\nB3:Thái thịt bò lát mỏng.\nB4:Chan nước dùng vào tô với bánh phở và thịt.', '1755584538_68a4181a837f3.jpg', 'Phở bò là một trong những món ăn truyền thống nổi tiếng nhất của ẩm thực Việt Nam, được xem như “linh hồn” của bữa sáng và cũng là niềm tự hào với bạn bè quốc tế. Món ăn nổi bật với phần nước dùng trong, ngọt thanh, được ninh từ xương bò trong nhiều giờ liền, hòa quyện cùng hương thơm của quế, hồi, gừng và hành nướng. Chính sự kết hợp tinh tế này tạo nên vị nước phở đậm đà, dậy mùi đặc trưng khó lẫn.', '2025-08-18 16:42:37', '2025-08-19 13:22:18', NULL);
INSERT INTO `meals` VALUES (23, 'Cơm gà', 13, 16, 'B1:Luộc gà với gừng.\nB2:Nấu cơm bằng nước luộc gà.\nB3:Xé gà thành sợi.\nB4:Ăn kèm dưa leo và cơm.', '1755584135_68a41687f4130.jpg', 'Cơm gà là một món ăn quen thuộc nhưng luôn tạo được sức hấp dẫn nhờ sự kết hợp hài hòa giữa hạt cơm dẻo thơm và thịt gà mềm ngọt. Thịt gà được luộc hoặc hấp chín vừa tới, giữ được độ ngọt tự nhiên, sau đó xé hoặc chặt miếng. Phần cơm thường được nấu cùng nước luộc gà và chút mỡ hành để hạt cơm vàng óng, thơm béo và đậm đà hương vị. Khi bày ra đĩa, cơm gà thường ăn kèm với rau sống, dưa leo, thêm chén nước chấm chua ngọt hoặc gừng giã để làm nổi bật vị ngon.', '2025-08-18 16:46:41', '2025-08-22 21:56:14', NULL);
INSERT INTO `meals` VALUES (24, 'Cá hồi nướng', 8, 3, 'B1:Rửa sạch cá hồi và măng tây.\nB2:Ướp cá hồi với muối, tiêu, nước chanh. B3:Nướng 10–15 phút.\nB4:Ăn kèm măng tây nướng.', '1755583768_68a41518b6c11.jpg', 'Cá hồi nướng là một món ăn sang trọng, giàu dinh dưỡng và được nhiều người ưa chuộng bởi hương vị thơm ngon, hấp dẫn. Miếng cá hồi tươi được tẩm ướp với các loại gia vị như muối, tiêu, tỏi, chanh hoặc thảo mộc, sau đó nướng chín vàng đều, giữ trọn vị ngọt tự nhiên và độ béo ngậy đặc trưng. Khi vừa chín tới, cá hồi mềm, mọng nước, lớp ngoài hơi giòn, tỏa ra hương thơm quyến rũ khiến thực khách khó lòng cưỡng lại.', '2025-08-18 16:57:42', '2025-08-19 13:09:28', NULL);
INSERT INTO `meals` VALUES (25, 'Sinh tố chuối', 12, 17, 'B1:Bóc vỏ chuối.\nB2:Cho chuối và sữa hạnh nhân vào máy xay.\nB3:Xay nhuyễn.\nB4:Đổ ra ly và thưởng thức.', '1755583510_68a414163ad97.png', 'Sinh tố chuối là một thức uống mát lạnh, thơm ngon và rất giàu dinh dưỡng, thường được nhiều người lựa chọn cho bữa sáng nhanh gọn hoặc làm món giải khát trong những ngày nắng nóng. Với nguyên liệu chính là chuối chín, sinh tố mang vị ngọt tự nhiên, béo ngậy khi kết hợp cùng sữa tươi hoặc sữa chua, tạo nên hương vị dịu nhẹ, dễ uống và phù hợp với mọi lứa tuổi.', '2025-08-18 16:59:49', '2025-08-19 13:07:35', NULL);
INSERT INTO `meals` VALUES (26, 'Canh bí đỏ tôm', 13, 5, 'B1:Gọt vỏ bí đỏ, cắt miếng vừa ăn.\nB2:Rửa sạch tôm, lột vỏ, băm nhuyễn một nửa.\nB3:Phi hành, xào tôm băm cho thơm.\nB4:Thêm nước, cho bí đỏ vào nấu mềm.\nB5: Cho tôm còn lại vào, nêm gia vị vừa ăn.', '1755583373_68a4138d6b0fc.png', 'Canh bí đỏ tôm là một món ăn dân dã, quen thuộc trong bữa cơm gia đình Việt Nam, vừa thơm ngon lại bổ dưỡng. Món ăn được nấu từ những miếng bí đỏ chín mềm, ngọt tự nhiên, kết hợp cùng vị tươi ngọt của tôm, tạo nên hương vị hài hòa, dễ ăn và hấp dẫn. Nước canh trong, ngọt thanh, dậy mùi thơm nhẹ của hành ngò, khiến người thưởng thức cảm thấy ấm lòng và ngon miệng.', '2025-08-18 17:02:54', '2025-09-24 15:55:37', '2025-09-24 15:55:37');
INSERT INTO `meals` VALUES (27, 'Cá sấu chiên giòn', 16, 3, 'Chiên cá sấu\nBới cơm', '1755846796_68a8188c3ea34.jpg', NULL, '2025-08-22 14:13:16', '2025-08-22 22:23:10', '2025-08-22 22:23:10');
INSERT INTO `meals` VALUES (28, 'Cá Sấu Luộc', 1, 3, 'Lột da cá sấu\nLuộc 1 tiếng', '1755875918_68a88a4e0d929.jpg', NULL, '2025-08-22 15:19:06', '2025-08-22 22:23:06', '2025-08-22 22:23:06');
INSERT INTO `meals` VALUES (29, 'Bánh mì trứng giòn', 18, 1, 'Lấy bánh mì, nướng giòn\nPhết bơ tươi\nChiên trứng', '1756087227_68abc3bb8e211.png', 'Một bữa sáng đơn giản', '2025-08-24 19:29:52', '2025-08-25 20:16:55', '2025-08-25 20:16:55');
INSERT INTO `meals` VALUES (30, 'Bánh mì trứng bơ', 18, 1, 'Bánh mì\nChiên trứng\nPhết bơ', '1756087202_68abc3a2ba46d.jpg', 'Một bữa sáng đơn giản', '2025-08-24 19:55:52', '2025-08-25 20:16:53', '2025-08-25 20:16:53');
INSERT INTO `meals` VALUES (31, 'Gà tẩm mật ong và tỏi', 13, 6, 'Ướp gà\nChiên', '1756087190_68abc39675fe1.jpg', 'Món ăn tuyệt vời', '2025-08-24 22:09:37', '2025-08-25 20:16:44', '2025-08-25 20:16:44');
INSERT INTO `meals` VALUES (32, 'cá sấu áp chảo', 19, 3, 'ướp cá sấu\náp chảo\nbỏ ra dĩa', '1756089613_68abcd0d46ca8.jpg', 'Thịt cá sấu trắng ngọt, mềm thịt, áp chảo nhanh giữ ẩm, ngon lạ vị – món protein thuần, ít béo, dành cho bữa tối độc đáo.', '2025-08-25 09:40:13', '2025-08-25 20:16:42', '2025-08-25 20:16:42');
INSERT INTO `meals` VALUES (33, 'Đà điểu chiên dòn', 6, 1, NULL, '1756091251_68abd37390b39.jpg', NULL, '2025-08-25 10:07:31', '2025-08-25 20:16:39', '2025-08-25 20:16:39');
